MT::Combinatorics c(N, mod);
void solve(int CASE)
{
	ll n, x; cin >> n >> x;
	var add = vector<ll>();
	var mul = vector<ll>();
	fa(i, 1, n) {
		string s; cin >> s;
		ll x = stoll(string(s.begin() + 1, s.end()));
		if (s[0] == '+')add.pb(x);
		else if (s[0] == '-')add.pb((-x + mod) % mod);
		else if (s[0] == 'x')mul.pb(x);
		else mul.pb(Math::inv(x, mod));
	}

	ll all_mul = 1, all_sum = 0;
	for (ll x : mul)all_mul = all_mul * x % mod;
	for (ll x : add)all_sum = (all_sum + x) % mod;

	ll m = mul.size();
	mul.insert(mul.begin(), { 1 });
	var dp = Vec2<ll>(m + 1, m + 1); // 前 i 个 mul 中，选 j 个的所有乘积之和
	dp[0][0] = 1;
	fa(i, 1, m) {
		fa(j, 0, i - 1) {
			dp[i][j + 1] = (dp[i][j + 1] + dp[i - 1][j] * mul[i] % mod) % mod;
			dp[i][j] = (dp[i][j] + dp[i - 1][j]) % mod;
		}
	}

	ll e = 0;
	fa(i, 0, m) {
		ll inv = Math::inv(c.lucas(m, i), mod); // m 个数中选 i 个，有 C(m, i) 中选法
		e = (e + dp[m][i] * inv % mod) % mod;
	}
	ll inv = Math::inv(m + 1, mod); // 一个加法操作后面跟了 k 个乘法操作的概率均为 1 / (m + 1)
	e = e * inv % mod;

	ll ans = (x * all_mul % mod + all_sum * e % mod) % mod;
	cout << ans << endl;
	return;
}
